import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"银精","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/银精.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/银精.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/银精.md"};function l(i,a,p,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"银精",tabindex:"-1"},[s("银精 "),e("a",{class:"header-anchor",href:"#银精","aria-label":'Permalink to "银精"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),o('<h1 id="银精-1" tabindex="-1">银精 <a class="header-anchor" href="#银精-1" aria-label="Permalink to &quot;银精&quot;">​</a></h1><p>银精</p><p>价格：500分<br> 本质：特异本质<br> 碣石剩谈。一宅每多鬼怪。有人买之。夜宿其中。遥闻嘈嘈人语。起听。在西壁下。其语谓吾軰主来矣。似庆贺者。顷之。又闻愁叹声。谓相聚多年。今将分离矣。主人暗喜。粪有所见。忽见一白衣老人至曰。吾乃银精也。壁下有银若干。待公久矣。任君掘出营运。惟吾银精不可凿。亦不可熔化。倘得存守。且能増益多金。次日。果于壁下掘银若千锭。内一锭。晶光夺目。识为银精。<br> 效果：<br> 一两白银，晶光夺目，名为银精，银矿之根，将其埋与地下，则数目倍增。<br> 在年初/影片开始时，将银精埋于地下，并花费1min焚香祷告，一年/一影片结束时挖出，银精便可额外增生三十六倍（获得36两999纯银），每额外多埋藏一年，增加数量将会累加（即第二年会变成72倍，即72两999纯银，第三年变为108两999纯银）<br> 三个九的银价大概在5.58元 ，1分1000远，10万元可购买约1800克银子，1.8kg 为36两999纯银</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
